const item = $input.first().json;
const igBusinessId = $getWorkflowStaticData('global').igBusinessId;

if (!item || item.error) {
  return [{ json: { error: 'Failed to fetch insights', raw: item } }];
}

const data = item.data || [];
const metrics = {};

for (const metric of data) {
  const values = metric.values || [];
  if (values.length > 0) {
    const latestValue = values[values.length - 1];
    metrics[metric.name] = latestValue.value;
  }
}

return [{
  json: {
    date: metrics.end_time || new Date().toISOString().split('T')[0],
    igBusinessId: igBusinessId,
    followerCount: metrics.follower_count || 0,
    impressions: metrics.impressions || 0,
    reach: metrics.reach || 0,
    profileViews: metrics.profile_views || 0,
    measuredAt: new Date().toISOString()
  }
}];

const current = $input.first().json;
const yesterday = $input.all()[1]?.json || null;

if (!yesterday) {
  return [{ json: { ...current, spikeDetected: false, reason: 'No prior data for comparison' } }];
}

const thresholds = $getWorkflowStaticData('global').thresholds || {
  followerSpikePct: 10,
  reachSpikePct: 50,
  impressionSpikePct: 50
};

const changes = {};
let spikeDetected = false;
let spikeReasons = [];

const metrics = ['followerCount', 'impressions', 'reach', 'profileViews'];
for (const metric of metrics) {
  const currentVal = current[metric] || 0;
  const prevVal = yesterday[metric] || 0;

  if (prevVal > 0) {
    const pctChange = ((currentVal - prevVal) / prevVal) * 100;
    changes[metric + 'ChangePct'] = Math.round(pctChange * 10) / 10;

    if (metric === 'followerCount' && Math.abs(pctChange) >= thresholds.followerSpikePct) {
      spikeDetected = true;
      spikeReasons.push(`Followers ${pctChange > 0 ? 'up' : 'down'} ${Math.abs(pctChange).toFixed(1)}% (${currentVal} vs ${prevVal})`);
    }
    if (metric === 'reach' && Math.abs(pctChange) >= thresholds.reachSpikePct) {
      spikeDetected = true;
      spikeReasons.push(`Reach ${pctChange > 0 ? 'up' : 'down'} ${Math.abs(pctChange).toFixed(1)}%`);
    }
    if (metric === 'impressions' && Math.abs(pctChange) >= thresholds.impressionSpikePct) {
      spikeDetected = true;
      spikeReasons.push(`Impressions ${pctChange > 0 ? 'up' : 'down'} ${Math.abs(pctChange).toFixed(1)}%`);
    }
  }
}

return [{
  json: {
    ...current,
    ...changes,
    spikeDetected: spikeDetected,
    spikeReasons: spikeReasons.join('; '),
    yesterdayFollowers: yesterday.followerCount
  }
}];

const item = $input.first().json;

const summary = `📊 Daily Analytics (${item.date})
Followers: ${item.followerCount}
Impressions: ${item.impressions}
Reach: ${item.reach}
Profile Views: ${item.profileViews}`;

const dailyLog = $getWorkflowStaticData('global').dailyLog || [];
dailyLog.push({
  date: item.date,
  summary: summary,
  recordedAt: new Date().toISOString()
});
if (dailyLog.length > 90) dailyLog.shift();
$getWorkflowStaticData('global').dailyLog = dailyLog;

console.log(summary);
return [{ json: { status: 'logged', date: item.date } }];
